*�����������������Juniform samplerBuffer sOffsets;
uniform vec2 uScreenRes;
uniform vec2 uSingleInputRes;
uniform float uBezel;

out vec4 fragColor;
void main()
{
    // Code very similar to remapping (glslmulti1) TOP
    // It handles only the UVs for later use with a remap TOP

    vec2 outputRes = uTDOutputInfo.res.zw;
    vec2 totalGrid = outputRes / uScreenRes;

    // Bezel handling
    vec2 extraPx = totalGrid * vec2(uBezel);
	vec2 scale = (outputRes + extraPx) / outputRes;

    vec2 currPixel = vUV.st * outputRes;
	vec2 gridCoord = floor(currPixel / uScreenRes);

	// Scale each screen from center to handle eventual bezel
	vec2 gridOffset = 1.0 / totalGrid;
	gridOffset = gridOffset / 2.0 + (gridCoord * gridOffset);
	vec2 vUVScale = vUV.st - gridOffset;
	vUVScale = vUVScale * (1.0 / max(scale.x, scale.y));
	vUVScale = vUVScale + gridOffset;

    // Which screen element are we in
    currPixel = vUVScale * outputRes;
    float currScreen = int(currPixel.x / uScreenRes.x) + (totalGrid.y - 1 - int(currPixel.y / uScreenRes.y)) * totalGrid.x;

    vec4 chopBufferData = texelFetch(sOffsets, int(currScreen));
    float inputId = chopBufferData.r;

    vec2 sourceGrid = uSingleInputRes / uScreenRes;
    vec2 gridScale = totalGrid / sourceGrid;

    vec2 startOffset = chopBufferData.ba;
    vec2 screenUVSize = 1.0 / totalGrid;

    vec2 offset = vUVScale - vec2(int(gridCoord.x), int(gridCoord.y)) * screenUVSize;
    offset = (offset*gridScale + startOffset);

    float isAssigned = step(0.5, chopBufferData.g);
    fragColor = TDOutputSwizzle(vec4(offset.s, offset.t, inputId, 1.0) * isAssigned);
}

